import{_ as i,c as e,o as s,ah as t}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"GitHub 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"github-guide.md","filePath":"github-guide.md"}'),l={name:"github-guide.md"};function h(r,a,n,o,d,k){return s(),e("div",null,a[0]||(a[0]=[t(`<h1 id="github-使用指南" tabindex="-1">GitHub 使用指南 <a class="header-anchor" href="#github-使用指南" aria-label="Permalink to “GitHub 使用指南”">​</a></h1><h2 id="_01-1-简介" tabindex="-1">01.1- 简介 <a class="header-anchor" href="#_01-1-简介" aria-label="Permalink to “01.1- 简介”">​</a></h2><p>GitHub 是全球最大的代码托管平台，为开发者提供了强大的版本控制、协作开发和项目管理功能。</p><h2 id="_01-2-基础概念" tabindex="-1">01.2- 基础概念 <a class="header-anchor" href="#_01-2-基础概念" aria-label="Permalink to “01.2- 基础概念”">​</a></h2><h3 id="_01-21-仓库-repository" tabindex="-1">01.21- 仓库（Repository） <a class="header-anchor" href="#_01-21-仓库-repository" aria-label="Permalink to “01.21- 仓库（Repository）”">​</a></h3><p>仓库是项目的存储空间，包含项目的所有文件、文件夹和每个文件的修订历史。</p><h3 id="_01-22-分支-branch" tabindex="-1">01.22- 分支（Branch） <a class="header-anchor" href="#_01-22-分支-branch" aria-label="Permalink to “01.22- 分支（Branch）”">​</a></h3><p>分支允许您在不影响主分支的情况下开发新功能或修复问题。</p><h3 id="_01-23-提交-commit" tabindex="-1">01.23- 提交（Commit） <a class="header-anchor" href="#_01-23-提交-commit" aria-label="Permalink to “01.23- 提交（Commit）”">​</a></h3><p>提交是对文件所做的更改的记录，每次提交都会生成一个唯一的 ID。</p><h3 id="_01-24-pull-request" tabindex="-1">01.24- Pull Request <a class="header-anchor" href="#_01-24-pull-request" aria-label="Permalink to “01.24- Pull Request”">​</a></h3><p>Pull Request 是请求将您的更改合并到主分支的请求，便于代码审查和讨论。</p><h2 id="_01-3-快速开始" tabindex="-1">01.3- 快速开始 <a class="header-anchor" href="#_01-3-快速开始" aria-label="Permalink to “01.3- 快速开始”">​</a></h2><h3 id="_01-31-创建账户" tabindex="-1">01.31- 创建账户 <a class="header-anchor" href="#_01-31-创建账户" aria-label="Permalink to “01.31- 创建账户”">​</a></h3><p>访问 <a href="https://github.com" target="_blank" rel="noreferrer">GitHub 官网</a> 注册账户。</p><h3 id="_01-32-创建仓库" tabindex="-1">01.32- 创建仓库 <a class="header-anchor" href="#_01-32-创建仓库" aria-label="Permalink to “01.32- 创建仓库”">​</a></h3><ol><li>点击右上角的 &quot;+&quot; 按钮</li><li>选择 &quot;New repository&quot;</li><li>填写仓库名称和描述</li><li>选择公开或私有</li><li>点击 &quot;Create repository&quot;</li></ol><h3 id="_01-33-克隆仓库" tabindex="-1">01.33- 克隆仓库 <a class="header-anchor" href="#_01-33-克隆仓库" aria-label="Permalink to “01.33- 克隆仓库”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-创建分支" tabindex="-1">01.34- 创建分支 <a class="header-anchor" href="#_01-34-创建分支" aria-label="Permalink to “01.34- 创建分支”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-提交更改" tabindex="-1">01.35- 提交更改 <a class="header-anchor" href="#_01-35-提交更改" aria-label="Permalink to “01.35- 提交更改”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;添加新功能&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-创建-pull-request" tabindex="-1">01.36- 创建 Pull Request <a class="header-anchor" href="#_01-36-创建-pull-request" aria-label="Permalink to “01.36- 创建 Pull Request”">​</a></h3><p>在 GitHub 网页上创建 Pull Request，等待审核和合并。</p><h2 id="_01-4-常用操作" tabindex="-1">01.4- 常用操作 <a class="header-anchor" href="#_01-4-常用操作" aria-label="Permalink to “01.4- 常用操作”">​</a></h2><h3 id="_01-41-fork-项目" tabindex="-1">01.41- Fork 项目 <a class="header-anchor" href="#_01-41-fork-项目" aria-label="Permalink to “01.41- Fork 项目”">​</a></h3><p>Fork 允许您复制他人的项目到自己的账户下进行修改。</p><h3 id="_01-42-star-项目" tabindex="-1">01.42- Star 项目 <a class="header-anchor" href="#_01-42-star-项目" aria-label="Permalink to “01.42- Star 项目”">​</a></h3><p>Star 表示您喜欢该项目，方便日后查找。</p><h3 id="_01-43-watch-项目" tabindex="-1">01.43- Watch 项目 <a class="header-anchor" href="#_01-43-watch-项目" aria-label="Permalink to “01.43- Watch 项目”">​</a></h3><p>Watch 可以让您接收到项目的更新通知。</p><h3 id="_01-44-issues" tabindex="-1">01.44- Issues <a class="header-anchor" href="#_01-44-issues" aria-label="Permalink to “01.44- Issues”">​</a></h3><p>Issues 用于报告问题、请求功能或讨论想法。</p><h2 id="_01-5-最佳实践" tabindex="-1">01.5- 最佳实践 <a class="header-anchor" href="#_01-5-最佳实践" aria-label="Permalink to “01.5- 最佳实践”">​</a></h2><ol><li><strong>编写清晰的提交信息</strong> - 让其他人了解每次提交的目的</li><li><strong>使用分支开发</strong> - 不要直接在主分支上开发</li><li><strong>定期同步</strong> - 保持本地仓库与远程仓库同步</li><li><strong>代码审查</strong> - 通过 Pull Request 进行代码审查</li><li><strong>文档完善</strong> - 为项目添加 README 和必要的文档</li></ol><h2 id="_01-6-相关资源" tabindex="-1">01.6- 相关资源 <a class="header-anchor" href="#_01-6-相关资源" aria-label="Permalink to “01.6- 相关资源”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">GitHub 官方文档</a></li><li><a href="/91git.html">Git 基础教程</a></li><li><a href="/全部资源概述.html">全部资源概述</a></li></ul>`,38)]))}const b=i(l,[["render",h]]);export{c as __pageData,b as default};
